class PostgreSQLAdapter:
    def load_data(self, project: str, entity: str) -> dict: ...
    def save_data(self, project: str, entity: str, data: dict) -> None: ...

useAIElement({
  id: "new-task-btn",
  type: "button",
  label: "New Task",
  description: "Create a new task in the project",
  actions: [{
    label: "Create Task",
    toolName: "createTask",
    toolParams: ["name*", "description", "type"],
    endpoint: "/projects/{slug}/tasks",
    method: "POST"
  }]
});

useAIElement({
  id: "status-filter",
  type: "filter",
  label: "Status Filter",
  value: currentStatus,
  description: "Filter tasks by status",
  actions: [{
    label: "Filter",
    description: "Change status filter",
    available: true
  }]
});

useAIElement({
  id: "task-list",
  type: "list",
  label: "Tasks",
  data: { count: tasks.length, statuses: { TODO: 3, DONE: 5 } },
  description: "List of project tasks with status and dependencies"
});
